package com.nattechnologies.trastcms.plugins.saas; import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="saas_subscription") class SaasSubscription{@Id@Column(length=36)String id;@ManyToOne(fetch=FetchType.LAZY,optional=false)@JoinColumn(name="plan_id")SaasPlan plan;@Column(name="customer_id",length=36)String customerId;@Column(name="customer_email",nullable=false,length=190)String customerEmail;@Enumerated(EnumType.STRING)@Column(nullable=false,length=30)SubscriptionStatus status=SubscriptionStatus.ACTIVE;@Column(name="order_id",length=36)String orderId;@Column(name="started_at",nullable=false)Instant startedAt;@Column(name="trial_ends_at")Instant trialEndsAt;@Column(name="current_period_start",nullable=false)Instant currentPeriodStart;@Column(name="current_period_end")Instant currentPeriodEnd;@Column(name="cancel_at_period_end",nullable=false)boolean cancelAtPeriodEnd=false;@Column(name="cancelled_at")Instant cancelledAt;@Column(name="created_at",nullable=false)Instant createdAt;@PrePersist void create(){if(id==null)id=UUID.randomUUID().toString();createdAt=Instant.now();}}
